1	export type Coordinate = [number, number];
2	
3	const parseCoordinate = (cellString: string): Coordinate => {
4	  const [x, y] = cellString.split(",").map(Number);
5	  return [x, y];
6	};
7	
8	const NEIGHBOR_OFFSETS: Coordinate[] = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1]
12	];
13	
14	const formatCoordinate = (x: number, y: number): string => {
15	  return `${x},${y}`;
16	};
17	
18	const getNeighborCells = (x: number, y: number): string[] => {
19	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => formatCoordinate(x + dx, y + dy));
20	};
21	
22	const countLiveNeighbors = (cell: string, livingCells: Set<string>): number => {
23	  const [x, y] = parseCoordinate(cell);
24	  const neighborCells = getNeighborCells(x, y);
25	  let count = 0;
26	  for (const neighbor of neighborCells) {
27	    if (livingCells.has(neighbor)) {
28	      count++;
29	    }
30	  }
31	  return count;
32	};
33	
34	const shouldCellSurviveOrBeBorn = (isAlive: boolean, liveNeighborCount: number): boolean => {
35	  if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
36	    return true; // Cell survives with 2 or 3 neighbors
37	  }
38	  if (!isAlive && liveNeighborCount === 3) {
39	    return true; // Dead cell becomes alive with exactly 3 neighbors
40	  }
41	  return false;
42	};
