44	/**
45	 * Computes the next generation of cells in Conway's Game of Life.
46	 *
47	 * Cells are represented as strings in the format "x,y" where x and y are integers.
48	 *
49	 * Rules applied:
50	 * - Cell with < 2 neighbors dies (underpopulation)
51	 * - Cell with 2-3 neighbors survives
52	 * - Cell with > 3 neighbors dies (overpopulation)
53	 * - Dead cell with exactly 3 neighbors becomes alive (reproduction)
54	 *
55	 * @param cells Set of living cells as coordinate strings "x,y"
56	 * @returns Set of living cells in the next generation
57	 */
58	export function nextGeneration(cells: Set<string>): Set<string> {
59	  if (cells.size === 0) {
60	    return new Set();
61	  }
62	
63	  const cellsToCheck = new Set<string>();
64	
65	  // Add all living cells and their neighbors to check
66	  for (const cell of cells) {
67	    const [x, y] = parseCoordinate(cell);
68	    cellsToCheck.add(cell);
69	    for (const neighbor of getNeighborCells(x, y)) {
70	      cellsToCheck.add(neighbor);
71	    }
72	  }
73	
74	  const nextGen = new Set<string>();
75	
76	  // Check each cell and determine if it survives or is born
77	  for (const cell of cellsToCheck) {
78	    const liveNeighborCount = countLiveNeighbors(cell, cells);
79	    const isAlive = cells.has(cell);
80	
81	    if (shouldCellSurviveOrBeBorn(isAlive, liveNeighborCount)) {
82	      nextGen.add(cell);
83	    }
84	  }
85	
86	  return nextGen;
87	}
